/**
 * Canonical hashing contract — ADR-0009.
 *
 * Input is hashed exactly as given: UTF-8 encoded, no trimming, no
 * case-folding, no Unicode normalization. Output is lowercase hex SHA-256.
 * The generator, agent install specs, and any server template's comparison
 * logic must all produce the same hash for the same PIN string — that only
 * holds if every implementation follows this exact procedure.
 *
 * Uses Web Crypto (`crypto.subtle`), available unmodified in both browsers
 * and Node (>=19) — no import, no dependency, per the rationale in
 * docs/security/threat-model.md § Hash Generation.
 */
export async function sha256Hex(input: string): Promise<string> {
  const bytes = new TextEncoder().encode(input);
  const digest = await crypto.subtle.digest("SHA-256", bytes);
  return Array.from(new Uint8Array(digest))
    .map((byte) => byte.toString(16).padStart(2, "0"))
    .join("");
}

import { sha256Hex } from "./hash.ts";

/**
 * Verification contract — ADR-0004, refined by ADR-0009.
 *
 * Both the local-hash strategy and any custom server-mode strategy resolve
 * to this same shape. `reason` exists so the UI can distinguish "wrong
 * code" from "couldn't reach the server" (docs/ux/flows.md § Error States)
 * without either strategy needing to know about the other.
 */
export type VerifyResult =
  | { ok: true; token?: string }
  | { ok: false; reason?: "invalid" | "network" | "unknown" };

export type VerifyFn = (code: string) => Promise<VerifyResult>;

/**
 * Builds the default local-hash `VerifyFn`. Hashing follows the canonical
 * contract in hash.ts — no normalization beyond that. A local hash
 * comparison cannot fail for network reasons, so this verifier only ever
 * resolves `{ ok: true }` or `{ ok: false, reason: "invalid" }`.
 */
export function createLocalHashVerifier(expectedHash: string): VerifyFn {
  return async (code) => {
    const actualHash = await sha256Hex(code);
    return actualHash === expectedHash ? { ok: true } : { ok: false, reason: "invalid" };
  };
}

export interface VerifyConfig {
  expectedHash?: string;
  verify?: VerifyFn;
}

/**
 * Resolves a `{ expectedHash, verify }` config into the single `VerifyFn`
 * a session lifecycle actually calls. Supplying both or neither is a
 * configuration error (ADR-0009) — this always throws for either case
 * rather than silently picking a winner. Framework surfaces (e.g. the
 * React component in M2) decide *when* to call this — whether that's once
 * at construction or gated behind a dev-only check is a framework-layer
 * choice, not a core one; this function itself has no dev/prod branch.
 */
export function resolveVerifyFn(config: VerifyConfig): VerifyFn {
  const hasHash = config.expectedHash !== undefined;
  const hasVerify = config.verify !== undefined;

  if (hasHash === hasVerify) {
    throw new Error(
      hasHash
        ? "Access Gate: supply either `expectedHash` or `verify`, not both."
        : "Access Gate: supply either `expectedHash` or `verify` — no implicit default verification strategy."
    );
  }

  return hasHash ? createLocalHashVerifier(config.expectedHash as string) : (config.verify as VerifyFn);
}

/**
 * Session record schema and lifecycle — ADR-0008.
 *
 * This is the one and only shape any Access Gate surface (React hook,
 * vanilla snippet) writes. No other fields are ever added without revisiting
 * that ADR — in particular the raw PIN or hash is never part of this record
 * (ADR-0005).
 */
export type AccessGateSession = {
  /** epoch ms, set once at successful verification */
  unlockedAt: number;
  /** epoch ms; fixed at creation, or rewritten on each interaction under the sliding model */
  expiresAt: number;
  /** present only if the VerifyFn resolved one (server mode); absent in local-hash mode */
  token?: string;
};

/**
 * Creates a new session from a successful verification result. `timeoutMs`
 * sets the initial expiry; `now` is injectable for deterministic tests.
 *
 * `token` is included only when the verify result actually provided one —
 * a genuinely missing field, not a `token: undefined` key (ADR-0008).
 */
export function createSession(
  result: { token?: string },
  timeoutMs: number,
  now: number = Date.now()
): AccessGateSession {
  return {
    unlockedAt: now,
    expiresAt: now + timeoutMs,
    ...(result.token !== undefined ? { token: result.token } : {}),
  };
}

export function isExpired(session: AccessGateSession, now: number = Date.now()): boolean {
  return now >= session.expiresAt;
}

/**
 * Sliding-timeout model (opt-in activity tracking): rewrites `expiresAt`
 * relative to `now`, leaving `unlockedAt` and `token` untouched. Returns a
 * new object rather than mutating the input.
 */
export function touchExpiry(
  session: AccessGateSession,
  timeoutMs: number,
  now: number = Date.now()
): AccessGateSession {
  return { ...session, expiresAt: now + timeoutMs };
}

import type { AccessGateSession } from "./session.ts";

/** Structural subset of the Web Storage API — avoids depending on DOM lib types. */
export interface StorageLike {
  getItem(key: string): string | null;
  setItem(key: string, value: string): void;
  removeItem(key: string): void;
}

/** Minimal shape of the native `storage` event, enough to filter by key. */
export interface MinimalStorageEvent {
  key: string | null;
}

/** Structural subset of an event target that can fire `storage` events (i.e. `window`). */
export interface StorageEventTarget {
  addEventListener(type: "storage", listener: (event: MinimalStorageEvent) => void): void;
  removeEventListener(type: "storage", listener: (event: MinimalStorageEvent) => void): void;
}

export type StorageMode = "localStorage" | "sessionStorage" | "memory";

/**
 * Unified interface all three storage backends implement — ADR-0008.
 * `subscribe` fires `callback` when the session changes in another tab; it
 * is a real cross-tab mechanism only for `localStorage` (see
 * docs/architecture/overview.md § Cross-Tab Synchronization). For
 * `sessionStorage` and `memory` it never fires — that's correct behavior,
 * not a missing feature, since neither mode has anything to sync across
 * tabs to begin with.
 */
export interface SessionStore {
  get(): AccessGateSession | null;
  set(session: AccessGateSession): void;
  clear(): void;
  subscribe(callback: () => void): () => void;
}

export const DEFAULT_STORAGE_KEY = "access-gate:session";

const NOOP_UNSUBSCRIBE = () => {};

function isValidSession(value: unknown): value is AccessGateSession {
  if (typeof value !== "object" || value === null) return false;
  const v = value as Record<string, unknown>;
  return typeof v.unlockedAt === "number" && typeof v.expiresAt === "number";
}

export interface CreateSessionStoreOptions {
  storageKey?: string;
  /** Injectable for tests or non-global environments; defaults to the real global. Ignored for `"memory"`. */
  storage?: StorageLike;
  /** Injectable for tests; defaults to the real global. Ignored for `"memory"` and `"sessionStorage"` — see the `subscribe` note above. */
  eventTarget?: StorageEventTarget;
}

export function createSessionStore(mode: StorageMode, options: CreateSessionStoreOptions = {}): SessionStore {
  const storageKey = options.storageKey ?? DEFAULT_STORAGE_KEY;

  if (mode === "memory") return createMemoryStore();

  const storage = options.storage ?? getGlobalStorage(mode);
  const eventTarget = mode === "localStorage" ? options.eventTarget ?? getGlobalEventTarget() : undefined;
  return createWebStorageStore(mode, storageKey, storage, eventTarget);
}

function createMemoryStore(): SessionStore {
  let current: AccessGateSession | null = null;
  return {
    get: () => current,
    set: (session) => {
      current = session;
    },
    clear: () => {
      current = null;
    },
    subscribe: () => NOOP_UNSUBSCRIBE,
  };
}

function createWebStorageStore(
  mode: "localStorage" | "sessionStorage",
  storageKey: string,
  storage: StorageLike | undefined,
  eventTarget: StorageEventTarget | undefined
): SessionStore {
  function requireStorage(): StorageLike {
    if (!storage) {
      throw new Error(
        `Access Gate: ${mode} is not available in this environment. Pass a \`storage\` implementation explicitly, or use \`storage: "memory"\`.`
      );
    }
    return storage;
  }

  return {
    get() {
      const raw = requireStorage().getItem(storageKey);
      if (raw === null) return null;
      let parsed: unknown;
      try {
        parsed = JSON.parse(raw);
      } catch {
        return null; // corrupted entry reads as "no session", not a crash
      }
      return isValidSession(parsed) ? parsed : null;
    },
    set(session) {
      requireStorage().setItem(storageKey, JSON.stringify(session));
    },
    clear() {
      requireStorage().removeItem(storageKey);
    },
    subscribe(callback) {
      if (mode !== "localStorage" || !eventTarget) return NOOP_UNSUBSCRIBE;
      const handler = (event: MinimalStorageEvent) => {
        if (event.key === storageKey || event.key === null) callback();
      };
      eventTarget.addEventListener("storage", handler);
      return () => eventTarget.removeEventListener("storage", handler);
    },
  };
}

function getGlobalStorage(mode: "localStorage" | "sessionStorage"): StorageLike | undefined {
  const g = globalThis as unknown as { localStorage?: StorageLike; sessionStorage?: StorageLike };
  return mode === "localStorage" ? g.localStorage : g.sessionStorage;
}

function getGlobalEventTarget(): StorageEventTarget | undefined {
  const g = globalThis as unknown as Partial<StorageEventTarget>;
  if (typeof g.addEventListener !== "function" || typeof g.removeEventListener !== "function") return undefined;
  return g as StorageEventTarget;
}
